/// The disk-backed cache for user preferences
pub struct PreferencesCache {
    cache_dir: PathBuf,
    /// In-memory cache layer
    memory_cache: HashMap<String, UserPreferences>,
}

impl PreferencesCache {
    /// Create a new cache backed by the given directory
    pub fn new<P: AsRef<Path>>(cache_dir: P) -> Result<Self> {
        let cache_dir = cache_dir.as_ref().to_path_buf();
        fs::create_dir_all(&cache_dir)?;
        Ok(Self {
            cache_dir,
            memory_cache: HashMap::new(),
        })
    }

    fn file_path(&self, key: &str) -> PathBuf {
        // Sanitize key to prevent path traversal
        let safe_key: String = key
            .chars()
            .map(|c| if c.is_alphanumeric() || c == '_' || c == '-' { c } else { '_' })
            .collect();
        self.cache_dir.join(format!("{}.bin", safe_key))
    }

    /// Save user preferences to disk and memory cache
    pub fn save(&mut self, key: &str, prefs: &UserPreferences) -> Result<()> {
        // Validate before saving
        prefs.validate()?;

        let config = bincode::config::standard()
            .with_limit::<{ 10 * 1024 * 1024 }>(); // 10 MB limit

        let encoded = bincode::serde::encode_to_vec(prefs, config)
            .map_err(|e| CacheError::Serialize(Box::new(e)))?;

        let path = self.file_path(key);

        // Write atomically: write to temp file then rename
        let temp_path = path.with_extension("bin.tmp");
        fs::write(&temp_path, &encoded)?;
        fs::rename(&temp_path, &path)?;

        // Update memory cache
        self.memory_cache.insert(key.to_string(), prefs.clone());

        Ok(())
    }

    /// Load user preferences from memory cache or disk
    pub fn load(&mut self, key: &str) -> Result<UserPreferences> {
        // Check memory cache first
        if let Some(prefs) = self.memory_cache.get(key) {
            return Ok(prefs.clone());
        }

        // Load from disk
        let path = self.file_path(key);
        if !path.exists() {
            return Err(CacheError::CacheMiss(key.to_string()));
        }

        let data = fs::read(&path)?;

        let config = bincode::config::standard()
            .with_limit::<{ 10 * 1024 * 1024 }>(); // 10 MB limit

        let (prefs, _): (UserPreferences, _) = bincode::serde::decode_from_slice(&data, config)
            .map_err(|e| CacheError::Serialize(Box::new(e)))?;

        // Validate after deserialization
        prefs.validate()?;

        // Store in memory cache
        self.memory_cache.insert(key.to_string(), prefs.clone());

        Ok(prefs)
    }

    /// Remove a cached entry from both memory and disk
    pub fn remove(&mut self, key: &str) -> Result<()> {
        self.memory_cache.remove(key);
        let path = self.file_path(key);
        if path.exists() {
            fs::remove_file(&path)?;
        }
        Ok(())
    }

    /// Check if a key exists in the cache
    pub fn contains_key(&self, key: &str) -> bool {
        self.memory_cache.contains_key(key) || self.file_path(key).exists()
    }

    /// Clear all cached data
    pub fn clear(&mut self) -> Result<()> {
        self.memory_cache.clear();
        for entry in fs::read_dir(&self.cache_dir)? {
            let entry = entry?;
            let path = entry.path();
            if path.extension().and_then(|e| e.to_str()) == Some("bin") {
                fs::remove_file(path)?;
            }
        }
        Ok(())
    }

    /// List all cached keys (from disk)
    pub fn keys(&self) -> Result<Vec<String>> {
        let mut keys = Vec::new();
        for entry in fs::read_dir(&self.cache_dir)? {
            let entry = entry?;
            let path = entry.path();
            if path.extension().and_then(|e| e.to_str()) == Some("bin") {
                if let Some(stem) = path.file_stem().and_then(|s| s.to_str()) {
                    keys.push(stem.to_string());
                }
            }
        }
        Ok(keys)
    }

    /// Invalidate the in-memory cache, forcing next load from disk
    pub fn invalidate_memory(&mut self) {
        self.memory_cache.clear();
    }
}

