fn main() -> Result<()> {
    let cache_dir = std::env::temp_dir().join("rust_prefs_cache_demo");
    let mut cache = PreferencesCache::new(&cache_dir)?;

    // Create and save preferences for user "alice"
    let mut alice_prefs = default_preferences("alice");
    alice_prefs.theme = Theme::Custom {
        primary_color: "#3498db".to_string(),
        secondary_color: "#2ecc71".to_string(),
        font_size: 14,
    };
    alice_prefs.language = Language::French;
    alice_prefs
        .custom_settings
        .insert("sidebar_width".to_string(), "250".to_string());
    alice_prefs
        .custom_settings
        .insert("editor_mode".to_string(), "vim".to_string());
    alice_prefs.favorite_tags = vec![
        "rust".to_string(),
        "programming".to_string(),
        "systems".to_string(),
    ];

    println!("Saving Alice's preferences...");
    cache.save("alice", &alice_prefs)?;

    // Create and save preferences for user "bob"
    let mut bob_prefs = default_preferences("bob");
    bob_prefs.theme = Theme::Dark;
    bob_prefs.accessibility = AccessibilitySettings {
        high_contrast: true,
        screen_reader: true,
        reduced_motion: true,
        text_scale: 1.5,
    };
    bob_prefs.notifications.level = NotificationLevel::None;
    bob_prefs.privacy.profile_visible = false;

    println!("Saving Bob's preferences...");
    cache.save("bob", &bob_prefs)?;

    // Clear memory cache to force disk reads
    cache.invalidate_memory();

    // Load and verify
    println!("\nLoading Alice's preferences from disk...");
    let loaded_alice = cache.load("alice")?;
    assert_eq!(loaded_alice, alice_prefs);
    println!("  Username: {}", loaded_alice.username);
    println!("  Theme: {:?}", loaded_alice.theme);
    println!("  Language: {:?}", loaded_alice.language);
    println!("  Favorite tags: {:?}", loaded_alice.favorite_tags);
    println!("  Custom settings: {:?}", loaded_alice.custom_settings);

    println!("\nLoading Bob's preferences from disk...");
    let loaded_bob = cache.load("bob")?;
    assert_eq!(loaded_bob, bob_prefs);
    println!("  Username: {}", loaded_bob.username);
    println!("  Theme: {:?}", loaded_bob.theme);
    println!("  Accessibility: {:?}", loaded_bob.accessibility);
    println!("  Notifications level: {:?}", loaded_bob.notifications.level);

    // Second load should come from memory
    println!("\nLoading Alice's preferences from memory cache...");
    let loaded_alice_2 = cache.load("alice")?;
    assert_eq!(loaded_alice_2, alice_prefs);
    println!("  Loaded successfully from memory cache");

    // List all keys
    let keys = cache.keys()?;
    println!("\nCached keys: {:?}", keys);

    // Test validation: try saving invalid preferences
    println!("\nTesting validation...");
    let mut invalid_prefs = default_preferences("invalid");
    invalid_prefs.username = String::new(); // Empty username
    match cache.save("invalid", &invalid_prefs) {
        Err(CacheError::Validation(msg)) => {
            println!("  Correctly rejected empty username: {}", msg);
        }
        other => panic!("Expected validation error, got: {:?}", other),
    }

    let mut invalid_prefs2 = default_preferences("invalid2");
    invalid_prefs2.accessibility.text_scale = 100.0; // Out of range
    match cache.save("invalid2", &invalid_prefs2) {
        Err(CacheError::Validation(msg)) => {
            println!("  Correctly rejected invalid text_scale: {}", msg);
        }
        other => panic!("Expected validation error, got: {:?}", other),
    }

    let mut invalid_prefs3 = default_preferences("invalid3");
    invalid_prefs3.notifications.quiet_hours_start = Some(25); // Invalid hour
    match cache.save("invalid3", &invalid_prefs3) {
        Err(CacheError::Validation(msg)) => {
            println!("  Correctly rejected invalid quiet hours: {}", msg);
        }
        other => panic!("Expected validation error, got: {:?}", other),
    }

    // Test cache miss
    match cache.load("nonexistent") {
        Err(CacheError::CacheMiss(key)) => {
            println!("  Correctly reported cache miss for key: {}", key);
        }
        other => panic!("Expected cache miss, got: {:?}", other),
    }

    // Remove a key
    println!("\nRemoving Bob's preferences...");
    cache.remove("bob")?;
    assert!(!cache.contains_key("bob"));
    println!("  Bob's preferences removed");

    // Clean up
    cache.clear()?;
    fs::remove_dir_all(&cache_dir).ok();
    println!("\nCache cleared. Demo complete!");

    Ok(())
}

#[cfg(test)]
mod tests {
    use super::*;
    use tempfile::TempDir;

    fn test_cache() -> (PreferencesCache, TempDir) {
        let dir = TempDir::new().unwrap();
        let cache = PreferencesCache::new(dir.path()).unwrap();
        (cache, dir)
    }

    #[test]
    fn test_save_and_load() {
        let (mut cache, _dir) = test_cache();
        let prefs = default_preferences("testuser");
        cache.save("test", &prefs).unwrap();
        cache.invalidate_memory();
        let loaded = cache.load("test").unwrap();
        assert_eq!(loaded, prefs);
    }

    #[test]
    fn test_memory_cache() {
        let (mut cache, _dir) = test_cache();
        let prefs = default_preferences("testuser");
        cache.save("test", &prefs).unwrap();
        // Should load from memory without disk access
        let loaded = cache.load("test").unwrap();
        assert_eq!(loaded, prefs);
    }

    #[test]
    fn test_complex_preferences() {
        let (mut cache, _dir) = test_cache();
        let mut prefs = default_preferences("complex_user");
        prefs.theme = Theme::Custom {
            primary_color: "#ff0000".to_string(),
            secondary_color: "#00ff00".to_string(),
            font_size: 16,
        };
        prefs.language = Language::Other("Esperanto".to_string());
        prefs.notifications = NotificationPreferences {
            email_enabled: false,
            push_enabled: true,
            sms_enabled: true,
            level: NotificationLevel::All,
            quiet_hours_start: None,
            quiet_hours_end: None,
        };
        prefs
            .custom_settings
            .insert("key1".to_string(), "value1".to_string());
        prefs
            .custom_settings
            .insert("key2".to_string(), "value2".to_string());
        prefs.favorite_tags = vec!["tag1".to_string(), "tag2".to_string()];

        cache.save("complex", &prefs).unwrap();
        cache.invalidate_memory();
        let loaded = cache.load("complex").unwrap();
        assert_eq!(loaded, prefs);
    }

    #[test]
    fn test_validation_empty_username() {
        let (mut cache, _dir) = test_cache();
        let mut prefs = default_preferences("");
        prefs.username = String::new();
        assert!(matches!(
            cache.save("test", &prefs),
            Err(CacheError::Validation(_))
        ));
    }

    #[test]
    fn test_validation_text_scale() {
        let (mut cache, _dir) = test_cache();
        let mut prefs = default_preferences("user");
        prefs.accessibility.text_scale = 0.1;
        assert!(matches!(
            cache.save("test", &prefs),
            Err(CacheError::Validation(_))
        ));
    }

    #[test]
    fn test_validation_quiet_hours() {
        let (mut cache, _dir) = test_cache();
        let mut prefs = default_preferences("user");
        prefs.notifications.quiet_hours_start = Some(25);
        assert!(matches!(
            cache.save("test", &prefs),
            Err(CacheError::Validation(_))
        ));
    }

    #[test]
    fn test_validation_data_retention() {
        let (mut cache, _dir) = test_cache();
        let mut prefs = default_preferences("user");
        prefs.privacy.data_retention_days = 0;
        assert!(matches!(
            cache.save("test", &prefs),
            Err(CacheError::Validation(_))
        ));
    }

    #[test]
    fn test_cache_miss() {
        let (mut cache, _dir) = test_cache();
        assert!(matches!(
            cache.load("nonexistent"),
            Err(CacheError::CacheMiss(_))
        ));
    }

    #[test]
    fn test_remove() {
        let (mut cache, _dir) = test_cache();
        let prefs = default_preferences("user");
        cache.save("test", &prefs).unwrap();
        assert!(cache.contains_key("test"));
        cache.remove("test").unwrap();
        assert!(!cache.contains_key("test"));
    }

    #[test]
    fn test_clear() {
        let (mut cache, _dir) = test_cache();
        let prefs = default_preferences("user");
        cache.save("test1", &prefs).unwrap();
        cache.save("test2", &prefs).unwrap();
        cache.clear().unwrap();
        assert!(!cache.contains_key("test1"));
        assert!(!cache.contains_key("test2"));
    }

    #[test]
    fn test_keys() {
        let (mut cache, _dir) = test_cache();
        let prefs = default_preferences("user");
        cache.save("alpha", &prefs).unwrap();
        cache.save("beta", &prefs).unwrap();
        let mut keys = cache.keys().unwrap();
        keys.sort();
        assert_eq!(keys, vec!["alpha", "beta"]);
    }

    #[test]
    fn test_overwrite() {
        let (mut cache, _dir) = test_cache();
        let prefs1 = default_preferences("user1");
        let prefs2 = default_preferences("user2");
        cache.save("test", &prefs1).unwrap();
        cache.save("test", &prefs2).unwrap();
        let loaded = cache.load("test").unwrap();
        assert_eq!(loaded.username, "user2");
    }

    #[test]
    fn test_corrupted_data_rejected() {
        let (mut cache, _dir) = test_cache();
        let prefs = default_preferences("user");
        cache.save("test", &prefs).unwrap();

        // Corrupt the file
        let path = cache.file_path("test");
        fs::write(&path, b"corrupted data that is not valid bincode").unwrap();

        cache.invalidate_memory();
        assert!(cache.load("test").is_err());
    }

    #[test]
    fn test_path_traversal_sanitization() {
        let (cache, _dir) = test_cache();
        let path = cache.file_path("../../../etc/passwd");
        // Should not contain path traversal
        assert!(!path.to_str().unwrap().contains("../"));
    }

    #[test]
    fn test_custom_theme_validation() {
        let (mut cache, _dir) = test_cache();
        let mut prefs = default_preferences("user");
        prefs.theme = Theme::Custom {
            primary_color: String::new(),
            secondary_color: "#000".to_string(),
            font_size: 12,
        };
        assert!(matches!(
            cache.save("test", &prefs),
            Err(CacheError::Validation(_))
        ));
    }

    #[test]
    fn test_nan_text_scale_rejected() {
        let (mut cache, _dir) = test_cache();
        let mut prefs = default_preferences("user");
        prefs.accessibility.text_scale = f32::NAN;
        assert!(matches!(
            cache.save("test", &prefs),
            Err(CacheError::Validation(_))
        ));
    }
}